const axios = require('axios');
const cheerio = require('cheerio');

exports.fetchUrlMetadata = async (req, res) => {
    try {
        const urlToFetch = req.body.url;
        const response = await axios.get(urlToFetch);
        const $ = cheerio.load(response.data);

        let metadata = {};

        $('meta').each(function () {
            var metaName = $(this).attr('name');
            var metaContent = $(this).attr('content');
            var metaProperty = $(this).attr('property');

            if(metaName === 'description' || metaProperty === 'og:description') {
                metadata.description = metaContent;
            }

            if (!metadata.title && $('title').length) {
                metadata.title = $('title').eq(0).text();
            }

            if (metaProperty === 'og:title') {
                metadata.title = metaContent;
            }

            if (metaProperty === 'og:image') {
                metadata.image = metaContent;
            }

            if (metaProperty === 'og:url') {
                metadata.url = metaContent;
            }
        });

        res.status(200).send(metadata);
    } catch (error) {
        res.status(500).send({ error: 'Error fetching URL metadata' });
    }
};